// AI Cascade: Groq → Gemini → Mistral → Claude Haiku
// Configurar en Railway (servicio n8n) → Variables:
//   GROQ_API_KEY       console.groq.com    (gratis, 14 400 req/día)
//   GOOGLE_AI_KEY      aistudio.google.com (gratis, 1 500 req/día)
//   MISTRAL_API_KEY    console.mistral.ai  (free tier)
//   ANTHROPIC_API_KEY  console.anthropic.com (Claude Haiku — respaldo final)

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

const GROQ_KEY      = $env.GROQ_API_KEY      || '';
const GEMINI_KEY    = $env.GOOGLE_AI_KEY     || '';
const MISTRAL_KEY   = $env.MISTRAL_API_KEY   || '';
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY || '';

const SYSTEM = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

const USER_PROMPT = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[]\n}\n\nReglas:\n- summary: 1-2 frases, lenguaje ejecutivo.\n- findings: 2-5 observaciones técnicas clave (dimensionamiento, cobertura, compatibilidad eléctrica, normativa).\n- warnings: alertas críticas (voc fuera de rango, banco subdimensionado, incompatibilidad de voltaje, excedentes fuera de AGPE, etc). Vacío si no hay.\n- suggestions: 2-4 acciones recomendadas específicas.\n- NO inventes valores. Trabaja solo con los datos del payload.`;

function extractJSON(text) {
  const m = (text || '').match(/\{[\s\S]*\}/);
  if (!m) throw new Error('JSON no encontrado en respuesta');
  return JSON.parse(m[0]);
}

function buildResult(parsed, provider, usage) {
  return {
    summary: parsed.summary || '',
    findings: Array.isArray(parsed.findings) ? parsed.findings : [],
    warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
    suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
    provider,
    tokens: usage || null,
  };
}

// ── 1. Groq — Llama 3.3 70B ──────────────────────────────────────────────────
if (GROQ_KEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: { 'Authorization': `Bearer ${GROQ_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: 'llama-3.3-70b-versatile',
        max_tokens: 1024,
        temperature: 0.3,
        messages: [{ role: 'system', content: SYSTEM }, { role: 'user', content: USER_PROMPT }],
      },
      json: true,
    });
    const text = r.choices?.[0]?.message?.content || '';
    const parsed = extractJSON(text);
    const usage = r.usage ? { in: r.usage.prompt_tokens || 0, out: r.usage.completion_tokens || 0 } : null;
    return [{ json: buildResult(parsed, 'groq-llama3.3-70b', usage) }];
  } catch (_) { /* continúa con Gemini */ }
}

// ── 2. Gemini Flash ───────────────────────────────────────────────────────────
if (GEMINI_KEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_KEY}`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        system_instruction: { parts: [{ text: SYSTEM }] },
        contents: [{ role: 'user', parts: [{ text: USER_PROMPT }] }],
        generationConfig: { maxOutputTokens: 1024, temperature: 0.3 },
      },
      json: true,
    });
    const text = r.candidates?.[0]?.content?.parts?.[0]?.text || '';
    const parsed = extractJSON(text);
    const meta = r.usageMetadata;
    const usage = meta ? { in: meta.promptTokenCount || 0, out: meta.candidatesTokenCount || 0 } : null;
    return [{ json: buildResult(parsed, 'gemini-1.5-flash', usage) }];
  } catch (_) { /* continúa con Mistral */ }
}

// ── 3. Mistral Small ─────────────────────────────────────────────────────────
if (MISTRAL_KEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.mistral.ai/v1/chat/completions',
      headers: { 'Authorization': `Bearer ${MISTRAL_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: 'mistral-small-latest',
        max_tokens: 1024,
        temperature: 0.3,
        messages: [{ role: 'system', content: SYSTEM }, { role: 'user', content: USER_PROMPT }],
      },
      json: true,
    });
    const text = r.choices?.[0]?.message?.content || '';
    const parsed = extractJSON(text);
    const usage = r.usage ? { in: r.usage.prompt_tokens || 0, out: r.usage.completion_tokens || 0 } : null;
    return [{ json: buildResult(parsed, 'mistral-small', usage) }];
  } catch (_) { /* continúa con Claude Haiku */ }
}

// ── 4. Claude Haiku — respaldo definitivo ────────────────────────────────────
if (!ANTHROPIC_KEY) {
  throw new Error('Ningún proveedor AI disponible. Configura al menos una key en Railway: GROQ_API_KEY, GOOGLE_AI_KEY, MISTRAL_API_KEY o ANTHROPIC_API_KEY.');
}

const r = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': ANTHROPIC_KEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json',
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    system: SYSTEM,
    messages: [{ role: 'user', content: USER_PROMPT }],
  },
  json: true,
});

const text = (r.content || []).map(c => c.text || '').join('\n').trim();
const parsed = extractJSON(text);
const usage = r.usage ? { in: r.usage.input_tokens || 0, out: r.usage.output_tokens || 0 } : null;
return [{ json: buildResult(parsed, 'claude-haiku-4-5', usage) }];
